<template>
  <div class="agent-detail-container" v-loading="isLoading">
    <div class="page-header">
      <div class="title-section">
        <h1>{{ agent?.name || '智能体详情' }}</h1>
        <el-tag v-if="agent" size="large" :type="getAgentTypeTag(agent.agent_type)">
          {{ getAgentTypeLabel(agent.agent_type) }}
        </el-tag>
      </div>
      <div class="action-buttons">
        <el-button-group>
          <el-button type="primary" @click="$router.push(`/agents/${agentId}/edit`)" v-if="canEdit">
            <el-icon><edit /></el-icon> 编辑
          </el-button>
          <el-button type="success" @click="$router.push(`/agents/${agentId}/test`)">
            <el-icon><operation /></el-icon> 测试
          </el-button>
          <el-button @click="$router.push('/agents')">
            <el-icon><back /></el-icon> 返回列表
          </el-button>
        </el-button-group>
      </div>
    </div>

    <el-alert
      v-if="error"
      :title="error"
      type="error"
      :closable="false"
      show-icon
      class="alert-margin"
    />

    <template v-if="agent">
      <el-tabs>
        <el-tab-pane label="基本信息">
          <el-card class="info-card">
            <el-descriptions :column="2" border>
              <el-descriptions-item label="名称">{{ agent.name }}</el-descriptions-item>
              <el-descriptions-item label="ID">{{ agentId }}</el-descriptions-item>
              <el-descriptions-item label="类型">{{ getAgentTypeLabel(agent.agent_type) }}</el-descriptions-item>
              <el-descriptions-item label="模型">{{ agent.model_name }}</el-descriptions-item>
              <el-descriptions-item label="创建时间">{{ formatDate(agent.created_at) }}</el-descriptions-item>
              <el-descriptions-item label="更新时间">{{ formatDate(agent.updated_at) }}</el-descriptions-item>
              <el-descriptions-item label="状态">
                <el-tag :type="agent.is_active ? 'success' : 'danger'">
                  {{ agent.is_active ? '激活' : '未激活' }}
                </el-tag>
              </el-descriptions-item>
              <el-descriptions-item label="所有者">{{ agent.owner_name || '未知' }}</el-descriptions-item>
              <el-descriptions-item label="描述" :span="2">
                {{ agent.description || '无描述' }}
              </el-descriptions-item>
            </el-descriptions>
          </el-card>
        </el-tab-pane>

        <el-tab-pane label="A2A协议信息" v-if="agent.is_a2a_compliant">
          <el-card class="info-card">
            <el-descriptions :column="2" border>
              <el-descriptions-item label="A2A端点URL">
                <el-link type="primary" :href="agent.a2a_endpoint_url" target="_blank" v-if="agent.a2a_endpoint_url">
                  {{ agent.a2a_endpoint_url }}
                </el-link>
                <span v-else>未设置</span>
              </el-descriptions-item>
              <el-descriptions-item label="A2A版本">{{ agent.a2a_version || '1.0.0' }}</el-descriptions-item>
              <el-descriptions-item label="文档URL" v-if="agent.a2a_documentation_url">
                <el-link type="primary" :href="agent.a2a_documentation_url" target="_blank">
                  {{ agent.a2a_documentation_url }}
                </el-link>
              </el-descriptions-item>
            </el-descriptions>

            <div class="section-title">
              <h3>提供商信息</h3>
            </div>
            <pre v-if="agent.a2a_provider && Object.keys(agent.a2a_provider).length" class="json-display">{{ formatJSON(agent.a2a_provider) }}</pre>
            <el-empty v-else description="无提供商信息" />

            <div class="section-title">
              <h3>性能指标</h3>
            </div>
            <pre v-if="agent.a2a_performance && Object.keys(agent.a2a_performance).length" class="json-display">{{ formatJSON(agent.a2a_performance) }}</pre>
            <el-empty v-else description="无性能指标信息" />
          </el-card>
        </el-tab-pane>

        <el-tab-pane label="技能" v-if="agent.skills && agent.skills.length">
          <el-card class="info-card">
            <el-collapse>
              <el-collapse-item v-for="skill in agent.skills" :key="skill.id" :title="skill.name" :name="skill.id">
                <el-descriptions :column="2" border>
                  <el-descriptions-item label="技能ID">{{ skill.skill_id }}</el-descriptions-item>
                  <el-descriptions-item label="类型">{{ skill.skill_type }}</el-descriptions-item>
                  <el-descriptions-item label="描述" :span="2">{{ skill.description || '无描述' }}</el-descriptions-item>
                </el-descriptions>
                
                <div class="section-title">
                  <h4>参数</h4>
                </div>
                <pre v-if="skill.parameters && Object.keys(skill.parameters).length" class="json-display">{{ formatJSON(skill.parameters) }}</pre>
                <el-empty v-else description="无参数配置" />
                
                <div class="section-title">
                  <h4>输入输出模式</h4>
                </div>
                <el-descriptions :column="2" border>
                  <el-descriptions-item label="输入模式">
                    <el-tag v-for="mode in skill.input_modes" :key="mode" size="small" style="margin-right: 5px">
                      {{ mode }}
                    </el-tag>
                  </el-descriptions-item>
                  <el-descriptions-item label="输出模式">
                    <el-tag v-for="mode in skill.output_modes" :key="mode" size="small" style="margin-right: 5px">
                      {{ mode }}
                    </el-tag>
                  </el-descriptions-item>
                </el-descriptions>
              </el-collapse-item>
            </el-collapse>
          </el-card>
        </el-tab-pane>

        <el-tab-pane label="相关工作流">
          <el-card class="info-card">
            <div v-if="relatedWorkflows.length > 0">
              <el-table :data="relatedWorkflows" style="width: 100%">
                <el-table-column prop="name" label="工作流名称">
                  <template #default="scope">
                    <el-link
                      type="primary"
                      @click="$router.push(`/workflow/${scope.row.id}`)"
                    >
                      {{ scope.row.name }}
                    </el-link>
                  </template>
                </el-table-column>
                <el-table-column prop="type" label="类型" width="120" />
                <el-table-column prop="created_at" label="创建时间" width="180">
                  <template #default="scope">
                    {{ formatDate(scope.row.created_at) }}
                  </template>
                </el-table-column>
                <el-table-column label="操作" width="150">
                  <template #default="scope">
                    <el-button-group>
                      <el-button size="small" @click="$router.push(`/workflow/${scope.row.id}`)">
                        查看
                      </el-button>
                      <el-button size="small" type="success" @click="runWorkflow(scope.row.id)">
                        运行
                      </el-button>
                    </el-button-group>
                  </template>
                </el-table-column>
              </el-table>
            </div>
            <el-empty v-else description="没有使用此智能体的工作流" />
          </el-card>
        </el-tab-pane>
      </el-tabs>
    </template>
  </div>
</template>

<script>
import { ref, computed, onMounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { useAuthStore } from '@/store/auth'
import { useAgentStore } from '@/store/agent'
import { ElMessage } from 'element-plus'
import axios from 'axios'
import {
  Edit,
  Operation,
  Back,
  View,
  VideoPlay
} from '@element-plus/icons-vue'

export default {
  name: 'AgentDetail',
  components: {
    Edit,
    Operation,
    Back,
    View,
    VideoPlay
  },
  setup() {
    const route = useRoute()
    const router = useRouter()
    const authStore = useAuthStore()
    const agentStore = useAgentStore()
    
    const agentId = ref(route.params.id)
    const relatedWorkflows = ref([])
    
    // 从store获取状态
    const agent = computed(() => agentStore.currentAgent)
    const isLoading = computed(() => agentStore.isLoading)
    const error = computed(() => agentStore.error)
    
    // 当前用户是否可以编辑
    const canEdit = computed(() => {
      if (!agent.value || !authStore.user) return false
      return agent.value.owner === authStore.user.id || authStore.user.is_staff
    })
    
    // 获取智能体详情
    const fetchAgentDetail = async () => {
      await agentStore.fetchAgent(agentId.value)
      fetchRelatedWorkflows()
    }
    
    // 获取相关工作流
    const fetchRelatedWorkflows = async () => {
      try {
        const response = await axios.get(`/api/agents/${agentId.value}/workflows/`)
        relatedWorkflows.value = response.data.results || response.data
      } catch (err) {
        console.error('获取相关工作流失败', err)
      }
    }
    
    // 运行工作流
    const runWorkflow = async (workflowId) => {
      try {
        const response = await axios.post(`/api/workflows/${workflowId}/execute/`, {
          parameters: {}
        })
        
        if (response.data && response.data.instance_id) {
          ElMessage.success('工作流启动成功')
          router.push(`/workflow/instance/${response.data.instance_id}`)
        }
      } catch (err) {
        console.error('启动工作流失败', err)
        ElMessage.error('启动工作流失败，请稍后再试')
      }
    }
    
    // 格式化日期
    const formatDate = (dateString) => {
      if (!dateString) return '未知日期'
      const date = new Date(dateString)
      return date.toLocaleString('zh-CN', { 
        year: 'numeric', 
        month: '2-digit', 
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
      })
    }
    
    // 格式化JSON为美观的显示
    const formatJSON = (jsonObj) => {
      return JSON.stringify(jsonObj, null, 2)
    }
    
    // 获取智能体类型的标签类型
    const getAgentTypeTag = (type) => {
      const typeMap = {
        'gpt-3.5': 'info',
        'gpt-4': 'success',
        'claude-3': 'warning',
        'gemini': 'danger',
        'custom': 'primary',
        'a2a': ''
      }
      return typeMap[type] || ''
    }
    
    // 获取智能体类型的显示标签
    const getAgentTypeLabel = (type) => {
      const labelMap = {
        'gpt-3.5': 'GPT-3.5',
        'gpt-4': 'GPT-4',
        'claude-3': 'Claude 3',
        'gemini': 'Gemini',
        'custom': '自定义',
        'a2a': 'A2A兼容'
      }
      return labelMap[type] || type
    }
    
    // 生命周期钩子
    onMounted(() => {
      fetchAgentDetail()
    })
    
    return {
      agentId,
      agent,
      isLoading,
      error,
      relatedWorkflows,
      canEdit,
      formatDate,
      formatJSON,
      getAgentTypeTag,
      getAgentTypeLabel,
      runWorkflow
    }
  }
}
</script>

